import React, { useState } from "react";
import { Link } from "react-router-dom";

export default function Register() {
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [birthPlace, setBirthPlace] = useState("");
  const [birthDate, setBirthDate] = useState("");
  const [role, setRole] = useState("");

  const [firstNameError, setFirstNameError] = useState(false);
  const [lastNameError, setLastNameError] = useState(false);
  const [emailError, setEmailError] = useState(false);
  const [passwordError, setPasswordError] = useState(false);
  const [birthPlaceError, setBirthPlaceError] = useState(false);
  const [birthDateError, setBirthDateError] = useState(false);
  const [roleError, setRoleError] = useState(false);

  const [buttonText, setButtonText] = useState("Create Account");

  const validateForm = () => {
    let isValid = true;

    if (!firstName || firstName.trim().length < 2) {
      setFirstNameError(true);
      isValid = false;
    } else {
      setFirstNameError(false);
    }

    if (!lastName || lastName.trim().length < 2) {
      setLastNameError(true);
      isValid = false;
    } else {
      setLastNameError(false);
    }

    if (!email || !email.includes("@") || !email.includes(".")) {
      setEmailError(true);
      isValid = false;
    } else {
      setEmailError(false);
    }

    if (!password || password.length < 6) {
      setPasswordError(true);
      isValid = false;
    } else {
      setPasswordError(false);
    }

    if (!birthPlace || birthPlace.trim().length < 2) {
      setBirthPlaceError(true);
      isValid = false;
    } else {
      setBirthPlaceError(false);
    }

    if (!birthDate) {
      setBirthDateError(true);
      isValid = false;
    } else {
      setBirthDateError(false);
    }

    if (!role) {
      setRoleError(true);
      isValid = false;
    } else {
      setRoleError(false);
    }

    return isValid;
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (validateForm()) {
      setButtonText("Creating Account...");
      setTimeout(() => {
        alert(`Welcome ${role === "manager" ? "Manager" : "Worker"}! Registration successful!\n\nName: ${firstName} ${lastName}\nEmail: ${email}\nBirth Place: ${birthPlace}\nBirth Date: ${birthDate}`);
        setButtonText("Create Account");
      }, 1000);
    } else {
      setButtonText("❌ Complete all fields!");
      setTimeout(() => {
        setButtonText("Create Account");
      }, 1500);
    }
  };

  const handleRoleSelect = (selectedRole) => {
    setRole(selectedRole);
    if (roleError) setRoleError(false);
  };

  return (
    <div 
      className="relative w-full min-h-screen"
      style={{
        background: "linear-gradient(135deg, #14532d 0%, #000000 50%, #14532d 100%)",
        position: "fixed",
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        overflowY: "auto",
      }}
    >
      <div className="container mx-auto px-4 h-full">
        <div className="flex content-center items-center justify-center h-full min-h-screen">
          <div className="w-full lg:w-5/12 px-4 mt-32 pb-12">
            {/* Join Us Title */}
            <div className="text-center mb-6">
              <h1 className="text-5xl font-bold text-white mb-2">
                Join Us
              </h1>
              <div className="w-24 h-1 bg-green-500 mx-auto rounded-full"></div>
            </div>

            {/* Form Container - تصميم المستطيل القديم */}
            <div 
              className="relative flex flex-col min-w-0 break-words w-full mb-6 shadow-2xl border-0 overflow-hidden"
              style={{
                background: "rgba(0, 0, 0, 0.5)",
                backdropFilter: "blur(12px)",
                borderRadius: "24px",
                border: "1px solid rgba(74, 222, 128, 0.3)",
              }}
            >
              {/* Register Title */}
              <div className="text-center pt-8 pb-2">
                <h2 className="text-3xl font-bold text-white">
                  Register
                </h2>
                <p className="text-white/60 text-sm mt-2">
                  Create your account to get started
                </p>
              </div>

              <div className="flex-auto px-4 lg:px-10 py-6">
                <form onSubmit={handleSubmit}>
                  {/* First Name */}
                  <div className="mb-4">
                    <label className="block text-white text-sm font-semibold mb-1">
                      First Name
                    </label>
                    <div className="glowing-input">
                      <input 
                        type="text" 
                        placeholder="John" 
                        value={firstName} 
                        onChange={(e)=>setFirstName(e.target.value)} 
                        style={{
                          borderBottomColor: firstNameError ? "#ef4444" : "#2e7d32",
                        }}
                      />
                      <div className="focus-border"></div>
                    </div>
                    {firstNameError && <p className="text-red-400 text-xs mt-1">⚠️ First name is required</p>}
                  </div>

                  {/* Last Name */}
                  <div className="mb-4">
                    <label className="block text-white text-sm font-semibold mb-1">
                      Last Name
                    </label>
                    <div className="glowing-input">
                      <input 
                        type="text" 
                        placeholder="Doe" 
                        value={lastName} 
                        onChange={(e)=>setLastName(e.target.value)} 
                        style={{
                          borderBottomColor: lastNameError ? "#ef4444" : "#2e7d32",
                        }}
                      />
                      <div className="focus-border"></div>
                    </div>
                    {lastNameError && <p className="text-red-400 text-xs mt-1">⚠️ Last name is required</p>}
                  </div>

                  {/* Email */}
                  <div className="mb-4">
                    <label className="block text-white text-sm font-semibold mb-1">
                      Email
                    </label>
                    <div className="glowing-input">
                      <input 
                        type="email" 
                        placeholder="your@email.com" 
                        value={email} 
                        onChange={(e)=>setEmail(e.target.value)} 
                        style={{
                          borderBottomColor: emailError ? "#ef4444" : "#2e7d32",
                        }}
                      />
                      <div className="focus-border"></div>
                    </div>
                    {emailError && <p className="text-red-400 text-xs mt-1">⚠️ Please enter a valid email address</p>}
                  </div>

                  {/* Birth Place */}
                  <div className="mb-4">
                    <label className="block text-white text-sm font-semibold mb-1">
                      Birth Place
                    </label>
                    <div className="glowing-input">
                      <input 
                        type="text" 
                        placeholder="City, Country" 
                        value={birthPlace} 
                        onChange={(e)=>setBirthPlace(e.target.value)} 
                        style={{
                          borderBottomColor: birthPlaceError ? "#ef4444" : "#2e7d32",
                        }}
                      />
                      <div className="focus-border"></div>
                    </div>
                    {birthPlaceError && <p className="text-red-400 text-xs mt-1">⚠️ Birth place is required</p>}
                  </div>

                  {/* Birth Date */}
                  <div className="mb-4">
                    <label className="block text-white text-sm font-semibold mb-1">
                      Birth Date
                    </label>
                    <div className="glowing-input">
                      <input 
                        type="date" 
                        value={birthDate} 
                        onChange={(e)=>setBirthDate(e.target.value)} 
                        style={{
                          borderBottomColor: birthDateError ? "#ef4444" : "#2e7d32",
                          colorScheme: "dark",
                        }}
                      />
                      <div className="focus-border"></div>
                    </div>
                    {birthDateError && <p className="text-red-400 text-xs mt-1">⚠️ Birth date is required</p>}
                  </div>

                  {/* Password */}
                  <div className="mb-4">
                    <label className="block text-white text-sm font-semibold mb-1">
                      Password
                    </label>
                    <div className="glowing-input">
                      <input 
                        type="password" 
                        placeholder="••••••••" 
                        value={password} 
                        onChange={(e)=>setPassword(e.target.value)} 
                        style={{
                          borderBottomColor: passwordError ? "#ef4444" : "#2e7d32",
                        }}
                      />
                      <div className="focus-border"></div>
                    </div>
                    {passwordError && <p className="text-red-400 text-xs mt-1">⚠️ Password must be at least 6 characters</p>}
                  </div>

                  {/* Role Selection */}
                  <div className="mb-6">
                    <label className="block text-white text-sm font-semibold mb-3">
                      Register as:
                    </label>
                    <div className="flex gap-4">
                      <button
                        type="button"
                        onClick={() => handleRoleSelect("manager")}
                        className={`
                          flex-1 flex items-center justify-center gap-2 px-4 py-3 rounded-xl 
                          transition-all duration-300 font-semibold
                          ${role === "manager" 
                            ? "bg-green-600 text-white shadow-lg scale-105" 
                            : "bg-white/10 text-white/80 hover:bg-white/20 border border-white/20"}
                        `}
                      >
                        <i className="fas fa-chart-line text-lg"></i>
                        <span>Manager</span>
                      </button>

                      <button
                        type="button"
                        onClick={() => handleRoleSelect("worker")}
                        className={`
                          flex-1 flex items-center justify-center gap-2 px-4 py-3 rounded-xl 
                          transition-all duration-300 font-semibold
                          ${role === "worker" 
                            ? "bg-green-600 text-white shadow-lg scale-105" 
                            : "bg-white/10 text-white/80 hover:bg-white/20 border border-white/20"}
                        `}
                      >
                        <i className="fas fa-tools text-lg"></i>
                        <span>Worker</span>
                      </button>
                    </div>
                    {roleError && <p className="text-red-400 text-xs mt-2">⚠️ Please select a role</p>}
                  </div>

                  {/* Terms & Conditions */}
                  <div className="mb-6">
                    <label className="inline-flex items-center cursor-pointer">
                      <input
                        type="checkbox"
                        className="form-checkbox rounded text-green-500 w-5 h-5 bg-white/20 border-white/30"
                      />
                      <span className="ml-2 text-sm font-semibold text-white/80">
                        I agree with the{" "}
                        <a href="#pablo" className="text-green-400 hover:text-green-300" onClick={(e) => e.preventDefault()}>
                          Privacy Policy
                        </a>
                      </span>
                    </label>
                  </div>

                  {/* Submit Button */}
                  <div className="text-center mt-6">
                    <button
                      type="submit"
                      className="bg-green-700 hover:bg-green-600 text-white font-bold uppercase px-6 py-3 rounded-2xl shadow-xl hover:shadow-2xl outline-none focus:outline-none w-full ease-linear transition-all duration-300"
                    >
                      {buttonText}
                    </button>
                  </div>

                  {/* Sign In Link */}
                  <div className="text-center mt-6">
                    <p className="text-white/60 text-sm">
                      Already have an account?{" "}
                      <Link to="/auth/login" className="text-green-400 hover:text-green-300 font-semibold">
                        Sign In
                      </Link>
                    </p>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* CSS for glowing effect */}
      <style>{`
        .glowing-input {
          position: relative;
          width: 100%;
          margin: 0;
        }
        .glowing-input input {
          width: 100%;
          padding: 12px 0;
          background: transparent;
          border: none;
          border-bottom: 3px solid #2e7d32;
          color: white;
          font-size: 16px;
          outline: none;
          transition: all 0.3s ease;
        }
        .glowing-input input:focus {
          border-bottom-color: #00d8d0;
          outline: none;
          box-shadow: none;
        }
        .focus-border {
          position: absolute;
          bottom: 0;
          left: 0;
          width: 0;
          height: 3px;
          background: #00d8d0;
          box-shadow: 0 0 10px #34e734;
          transition: all 0.5s ease;
        }
        .glowing-input input:focus ~ .focus-border {
          width: 110%;
        }
        input:focus,
        input:focus-visible {
          outline: none !important;
          box-shadow: none !important;
        }
      `}</style>
    </div>
  );
}
